+import { createLogger } from '../utils/logger.js';
+import {
+  calculatePruningPositionInFile,
+  containsPruningSequence,
+  findLastPrunePoint,
+  logPruningDetection,
+} from '../utils/pruning-detector.js';
+
+const logger = createLogger('cast-output-hub');
